import{_ as a,o as t,c as e,Q as n}from"./chunks/framework.7705da0e.js";const b=JSON.parse('{"title":"设计模式","description":"设计模式","frontmatter":{"title":"设计模式","description":"设计模式","date":"2023-12-14T00:00:00.000Z","tags":["计算机科学"]},"headers":[],"relativePath":"posts/技术/设计模式.md","filePath":"posts/技术/设计模式.md"}'),r={name:"posts/技术/设计模式.md"},s=n(`<h2 id="设计模式的六大原则" tabindex="-1">设计模式的六大原则 <a class="header-anchor" href="#设计模式的六大原则" aria-label="Permalink to &quot;设计模式的六大原则&quot;">​</a></h2><p>对接口编程而不是对实现编程。 优先使用对象组合而不是继承。</p><p>设计模式的使用（solid）</p><ul><li>单一职责(Single Responsibility)</li><li>开闭原则（Open Close Principle）:对扩展开放，对修改关闭</li><li>里氏代换原则（Liskov Substitution Principle）：继承复用,子类替代父类出现。</li><li>迪米特法则（Law Of Demeter Principle）：一个实体应当尽量少地与其他实体之间发生相互作用，使得系统功能模块相对独立。</li><li>接口隔离原则（Interface Segregation Principle）：使用多个隔离的接口，比使用单个接口要好</li><li>依赖倒转原则（Dependence Inversion Principle）：针对接口编程，依赖于抽象而不依赖于具体。</li><li>合成复用原则（Composite Reuse Principle）：尽量使用合成/聚合的方式，而不是使用继承。</li></ul><h1 id="创建型" tabindex="-1">创建型 <a class="header-anchor" href="#创建型" aria-label="Permalink to &quot;创建型&quot;">​</a></h1><h2 id="工厂模式-factory-pattern" tabindex="-1">工厂模式（Factory Pattern） <a class="header-anchor" href="#工厂模式-factory-pattern" aria-label="Permalink to &quot;工厂模式（Factory Pattern）&quot;">​</a></h2><p>作用：创建复杂对象 应用：Hibernate 换数据库只需换方言和驱动 优缺点：拓展方便、类多 <img src="https://www.runoob.com/wp-content/uploads/2014/08/AB6B814A-0B09-4863-93D6-1E22D6B07FF8.jpg" alt=""></p><h2 id="抽象工厂模式-abstract-factory-pattern" tabindex="-1">抽象工厂模式（Abstract Factory Pattern） <a class="header-anchor" href="#抽象工厂模式-abstract-factory-pattern" aria-label="Permalink to &quot;抽象工厂模式（Abstract Factory Pattern）&quot;">​</a></h2><p>作用：创建一系列复杂对象 应用：1、QQ 换皮肤，一整套一起换。 2、生成不同操作系统的程序。 优缺点：拓展困难 <img src="https://www.runoob.com/wp-content/uploads/2014/08/3E13CDD1-2CD2-4C66-BD33-DECBF172AE03.jpg" alt=""></p><h2 id="单例模式-singleton-pattern" tabindex="-1">单例模式（Singleton Pattern） <a class="header-anchor" href="#单例模式-singleton-pattern" aria-label="Permalink to &quot;单例模式（Singleton Pattern）&quot;">​</a></h2><p>作用：创建一系列复杂对象 应用：饱汉、饿汉、DLC</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">## DLC例子</span></span>
<span class="line"><span style="color:#e1e4e8;">public class T {</span></span>
<span class="line"><span style="color:#e1e4e8;">	private static volatile T t;</span></span>
<span class="line"><span style="color:#e1e4e8;">	private T() {}</span></span>
<span class="line"><span style="color:#e1e4e8;">	public static T getT() {</span></span>
<span class="line"><span style="color:#e1e4e8;">		//DoubleChecking双重检测---&gt;避免不必要的同步</span></span>
<span class="line"><span style="color:#e1e4e8;">		if(null!=t) {</span></span>
<span class="line"><span style="color:#e1e4e8;">			return t;</span></span>
<span class="line"><span style="color:#e1e4e8;">		}</span></span>
<span class="line"><span style="color:#e1e4e8;">		synchronized (T.class) {</span></span>
<span class="line"><span style="color:#e1e4e8;">			if(null==t) {</span></span>
<span class="line"><span style="color:#e1e4e8;">				t=new T();</span></span>
<span class="line"><span style="color:#e1e4e8;">				//1、开辟空间 2、初始化对象信息 3、返回对象的地址给引用</span></span>
<span class="line"><span style="color:#e1e4e8;">				//这里可能会发生指令重排，导致返回给的对象是一个空对象，故volatile</span></span>
<span class="line"><span style="color:#e1e4e8;">			}</span></span>
<span class="line"><span style="color:#e1e4e8;">		}</span></span>
<span class="line"><span style="color:#e1e4e8;">		</span></span>
<span class="line"><span style="color:#e1e4e8;">		return t;</span></span>
<span class="line"><span style="color:#e1e4e8;">	}</span></span>
<span class="line"><span style="color:#e1e4e8;">}</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">## DLC例子</span></span>
<span class="line"><span style="color:#24292e;">public class T {</span></span>
<span class="line"><span style="color:#24292e;">	private static volatile T t;</span></span>
<span class="line"><span style="color:#24292e;">	private T() {}</span></span>
<span class="line"><span style="color:#24292e;">	public static T getT() {</span></span>
<span class="line"><span style="color:#24292e;">		//DoubleChecking双重检测---&gt;避免不必要的同步</span></span>
<span class="line"><span style="color:#24292e;">		if(null!=t) {</span></span>
<span class="line"><span style="color:#24292e;">			return t;</span></span>
<span class="line"><span style="color:#24292e;">		}</span></span>
<span class="line"><span style="color:#24292e;">		synchronized (T.class) {</span></span>
<span class="line"><span style="color:#24292e;">			if(null==t) {</span></span>
<span class="line"><span style="color:#24292e;">				t=new T();</span></span>
<span class="line"><span style="color:#24292e;">				//1、开辟空间 2、初始化对象信息 3、返回对象的地址给引用</span></span>
<span class="line"><span style="color:#24292e;">				//这里可能会发生指令重排，导致返回给的对象是一个空对象，故volatile</span></span>
<span class="line"><span style="color:#24292e;">			}</span></span>
<span class="line"><span style="color:#24292e;">		}</span></span>
<span class="line"><span style="color:#24292e;">		</span></span>
<span class="line"><span style="color:#24292e;">		return t;</span></span>
<span class="line"><span style="color:#24292e;">	}</span></span>
<span class="line"><span style="color:#24292e;">}</span></span></code></pre></div><h2 id="建造者模式-builder-pattern" tabindex="-1">建造者模式（Builder Pattern） <a class="header-anchor" href="#建造者模式-builder-pattern" aria-label="Permalink to &quot;建造者模式（Builder Pattern）&quot;">​</a></h2><p>关键：Meal类</p><p><img src="https://www.runoob.com/wp-content/uploads/2014/08/20210315-builder-pattern.svg" alt=""></p><h1 id="结构型" tabindex="-1">结构型 <a class="header-anchor" href="#结构型" aria-label="Permalink to &quot;结构型&quot;">​</a></h1><h2 id="原型模式-prototype-pattern" tabindex="-1">原型模式（Prototype Pattern） <a class="header-anchor" href="#原型模式-prototype-pattern" aria-label="Permalink to &quot;原型模式（Prototype Pattern）&quot;">​</a></h2><p>作用：创建重复的对象，同时又能保证性能。 实现： Cloneable接口</p><h2 id="重-适配器模式-adapter-pattern" tabindex="-1">[重]适配器模式（Adapter Pattern） <a class="header-anchor" href="#重-适配器模式-adapter-pattern" aria-label="Permalink to &quot;[重]适配器模式（Adapter Pattern）&quot;">​</a></h2><p>作用：结合了两个独立接口的功能 实现：适配器继承新接口，依赖旧接口。(MediaAdapter.java)</p><p><img src="https://www.runoob.com/wp-content/uploads/2014/08/20210223-adapter.png" alt=""></p><h2 id="桥接模式-bridge-pattern" tabindex="-1">桥接模式（Bridge Pattern） <a class="header-anchor" href="#桥接模式-bridge-pattern" aria-label="Permalink to &quot;桥接模式（Bridge Pattern）&quot;">​</a></h2><p>作用：抽象化与实现化解耦，使得二者可以独立变化 实现：抽象类依赖实现类。 <img src="https://www.runoob.com/wp-content/uploads/2014/08/20201015-bridge.svg" alt=""></p><h2 id="过滤器模式-filter、criteria-pattern" tabindex="-1">过滤器模式（Filter、Criteria Pattern） <a class="header-anchor" href="#过滤器模式-filter、criteria-pattern" aria-label="Permalink to &quot;过滤器模式（Filter、Criteria Pattern）&quot;">​</a></h2><p>作用：过滤 实现：就一个循环过滤...</p><h2 id="组合模式-composite-pattern" tabindex="-1">组合模式（Composite Pattern） <a class="header-anchor" href="#组合模式-composite-pattern" aria-label="Permalink to &quot;组合模式（Composite Pattern）&quot;">​</a></h2><p>作用：层次结构 实现：树。</p><h2 id="重-装饰器模式-decorator-pattern" tabindex="-1">[重]装饰器模式（Decorator Pattern） <a class="header-anchor" href="#重-装饰器模式-decorator-pattern" aria-label="Permalink to &quot;[重]装饰器模式（Decorator Pattern）&quot;">​</a></h2><p>作用：向一个现有的对象添加新的功能，同时又不改变其结构 实现：抽象类implements Shape 和 protected Shape decoratedShape;</p><p><img src="https://www.runoob.com/wp-content/uploads/2014/08/20210420-decorator-1-decorator-decorator.svg" alt=""></p><h2 id="外观模式-facade-pattern" tabindex="-1">外观模式（Facade Pattern） <a class="header-anchor" href="#外观模式-facade-pattern" aria-label="Permalink to &quot;外观模式（Facade Pattern）&quot;">​</a></h2><p>作用：隐藏系统的复杂性 实现：外观类持有对象并封装细节。</p><h2 id="享元模式-flyweight-pattern" tabindex="-1">享元模式（Flyweight Pattern） <a class="header-anchor" href="#享元模式-flyweight-pattern" aria-label="Permalink to &quot;享元模式（Flyweight Pattern）&quot;">​</a></h2><p>作用：减少创建对象的数量 实现：hashmap缓存等</p><h2 id="重-代理模式-proxy-pattern" tabindex="-1">[重]代理模式（Proxy Pattern） <a class="header-anchor" href="#重-代理模式-proxy-pattern" aria-label="Permalink to &quot;[重]代理模式（Proxy Pattern）&quot;">​</a></h2><p>作用：减少创建对象的数量 实现：代理类实现一样的接口并持有被代理对象。（与装饰器模式区别：不关心被代理对象状态。）</p><h1 id="行为型" tabindex="-1">行为型 <a class="header-anchor" href="#行为型" aria-label="Permalink to &quot;行为型&quot;">​</a></h1><h2 id="责任链模式-chain-of-responsibility-pattern" tabindex="-1">责任链模式（Chain of Responsibility Pattern） <a class="header-anchor" href="#责任链模式-chain-of-responsibility-pattern" aria-label="Permalink to &quot;责任链模式（Chain of Responsibility Pattern）&quot;">​</a></h2><p>作用：如果一个对象不能处理该请求，那么它会把相同的请求传给下一个接收者。降低耦合，灵活性，拓展性。 实现：Handler 里面聚合它自己</p><h2 id="重-命令模式-command-pattern" tabindex="-1">[重]命令模式（Command Pattern） <a class="header-anchor" href="#重-命令模式-command-pattern" aria-label="Permalink to &quot;[重]命令模式（Command  Pattern）&quot;">​</a></h2><p>作用：调用对象寻找可以处理该命令的合适的对象，并把该命令传给相应的对象，该对象执行命令</p><p><img src="https://www.runoob.com/wp-content/uploads/2014/08/20220427-command-1-command-1.svg" alt=""></p><h2 id="解释器模式-interpreter-pattern" tabindex="-1">解释器模式（Interpreter Pattern） <a class="header-anchor" href="#解释器模式-interpreter-pattern" aria-label="Permalink to &quot;解释器模式（Interpreter Pattern）&quot;">​</a></h2><p>作用：JAVA 中如果碰到可以用 expression4J 代替。 实现：</p><p><img src="https://www.runoob.com/wp-content/uploads/2014/08/interpreter_pattern_uml_diagram.jpg" alt=""></p><h2 id="迭代器模式-iterator-pattern" tabindex="-1">迭代器模式（Iterator Pattern） <a class="header-anchor" href="#迭代器模式-iterator-pattern" aria-label="Permalink to &quot;迭代器模式（Iterator Pattern）&quot;">​</a></h2><p><img src="https://www.runoob.com/wp-content/uploads/2014/08/202107-23-iterator-pattern.png" alt=""></p><h2 id="中介者模式-mediator-pattern" tabindex="-1">中介者模式（Mediator Pattern） <a class="header-anchor" href="#中介者模式-mediator-pattern" aria-label="Permalink to &quot;中介者模式（Mediator Pattern）&quot;">​</a></h2><p>作用： 中介类，该类通常处理不同类之间的通信 实现：</p><p><img src="https://www.runoob.com/wp-content/uploads/2014/08/mediator_pattern_uml_diagram.jpg" alt=""></p><h2 id="备忘录模式-memento-pattern" tabindex="-1">备忘录模式（Memento Pattern） <a class="header-anchor" href="#备忘录模式-memento-pattern" aria-label="Permalink to &quot;备忘录模式（Memento Pattern）&quot;">​</a></h2><p>相当于缓存：CareTaker持有的mementoList</p><p><img src="https://www.runoob.com/wp-content/uploads/2014/08/memento-20220601-memento.svg" alt=""></p><h2 id="重-观察者模式-observer-pattern" tabindex="-1">[重]观察者模式（Observer Pattern） <a class="header-anchor" href="#重-观察者模式-observer-pattern" aria-label="Permalink to &quot;[重]观察者模式（Observer Pattern）&quot;">​</a></h2><p>作用：当一个对象被修改时，则会自动通知依赖它的对象 实现：对象subject持有多个观察者，改变时触发更新。</p><p><img src="https://www.runoob.com/wp-content/uploads/2014/08/observer_pattern_uml_diagram.jpg" alt=""></p><h2 id="重-状态模式-state-pattern" tabindex="-1">[重]状态模式（State Pattern） <a class="header-anchor" href="#重-状态模式-state-pattern" aria-label="Permalink to &quot;[重]状态模式（State Pattern）&quot;">​</a></h2><p>作用：类的行为是基于它的状态改变的，条件、分支语句的代替者。 实现：context持有state接口</p><p><img src="https://www.runoob.com/wp-content/uploads/2014/08/state_pattern_uml_diagram.png" alt=""></p><h2 id="空对象模式-null-object-pattern" tabindex="-1">空对象模式（Null Object Pattern） <a class="header-anchor" href="#空对象模式-null-object-pattern" aria-label="Permalink to &quot;空对象模式（Null Object Pattern）&quot;">​</a></h2><p>空对象代替null,该空对象类将无缝地使用在需要检查空值的地方</p><p><img src="https://www.runoob.com/wp-content/uploads/2014/08/null_pattern_uml_diagram.jpg" alt=""></p><h2 id="重-策略模式-strategy-pattern" tabindex="-1">[重]策略模式（Strategy Pattern） <a class="header-anchor" href="#重-策略模式-strategy-pattern" aria-label="Permalink to &quot;[重]策略模式（Strategy Pattern）&quot;">​</a></h2><p>作用：类的行为或其算法可以在运行时更改，避免使用多重条件判断，扩展性良好。 实现：context持有策略接口，封装方法。策略较多时看：混合模式， <img src="https://www.runoob.com/wp-content/uploads/2014/08/strategy_pattern_uml_diagram.jpg" alt=""></p><h2 id="模板模式-template-pattern" tabindex="-1">模板模式（Template Pattern） <a class="header-anchor" href="#模板模式-template-pattern" aria-label="Permalink to &quot;模板模式（Template Pattern）&quot;">​</a></h2><p>作用：封装不变部分，扩展可变部分，提取公共代码，便于维护 实现：抽象父类控制行为，子类负责实现</p><p><img src="https://www.runoob.com/wp-content/uploads/2014/08/template_pattern_uml_diagram.jpg" alt=""></p><h2 id="访问者模式-visitor-pattern" tabindex="-1">访问者模式（Visitor Pattern） <a class="header-anchor" href="#访问者模式-visitor-pattern" aria-label="Permalink to &quot;访问者模式（Visitor Pattern）&quot;">​</a></h2><p>作用：不同的访问者类，不同的执行算法。 实现：被观察领域的接口方法传入访问者接口。</p><p><img src="https://www.runoob.com/wp-content/uploads/2014/08/visitor_pattern_uml_diagram.jpg" alt=""></p>`,70),p=[s];function l(o,i,c,h,d,u){return t(),e("div",null,p)}const P=a(r,[["render",l]]);export{b as __pageData,P as default};
